.breadcrumb {
  display: flex;
  align-items: center;
}

.list {
  display: flex;
  align-items: center;
  list-style: none;
  margin: 0;
  padding: 0;
  gap: var(--dimension-space-050);
}

.item {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
}

.item-inner {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-050);
}

.link {
  color: var(--color-foreground-secondary);
  text-decoration: none;
  padding: var(--dimension-space-025) var(--dimension-space-050);
  border-radius: var(--dimension-radius-050);
  transition: background-color var(--effect-motion-short-2), color var(--effect-motion-short-2);
}

.link:hover {
  background-color: var(--color-interaction-hover);
  color: var(--color-foreground-primary);
}

.link:active { background-color: var(--color-interaction-pressed); }

.link:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-space-025);
}

.separator {
  color: var(--color-foreground-tertiary);
  -webkit-user-select: none;
  user-select: none;
}

.current {
  color: var(--color-foreground-primary);
  padding: var(--dimension-space-025) var(--dimension-space-050);
}

import { Component, Prop, Event, EventEmitter, h, Host } from '@stencil/core';

export interface BreadcrumbItem {
  label: string;
  href?: string;
}

@Component({
  tag: 'ds-breadcrumb',
  styleUrl: 'Breadcrumb.css',
  scoped: true,
})
export class Breadcrumb {
  @Prop() items: BreadcrumbItem[] = [];
  @Prop() separator: string = '/';

  @Event() dsNavigate!: EventEmitter<{ item: BreadcrumbItem; index: number }>;

  private handleClick(item: BreadcrumbItem, index: number, e: MouseEvent) {
    if (!item.href) {
      e.preventDefault();
    }
    this.dsNavigate.emit({ item, index });
  }

  render() {
    return (
      <Host>
        <nav aria-label="Breadcrumb" class="breadcrumb">
          <ol class="list">
            {this.items.map((item, i) => {
              const isLast = i === this.items.length - 1;
              return (
                <li class="item" key={i}>
                  {isLast ? (
                    <span class="text-body-medium-emphasis current" aria-current="page">
                      {item.label}
                    </span>
                  ) : (
                    <span class="item-inner">
                      <a
                        href={item.href ?? '#'}
                        class="link text-body-medium"
                        onClick={e => this.handleClick(item, i, e)}
                      >
                        {item.label}
                      </a>
                      <span class="separator text-body-small" aria-hidden="true">
                        {this.separator}
                      </span>
                    </span>
                  )}
                </li>
              );
            })}
          </ol>
        </nav>
      </Host>
    );
  }
}
